def quick_estimate(
    daily_tasks: int,
    avg_tokens_per_task: int,
    price_per_m: float = 5.0,  # blended input+output
) -> dict:
    """Back-of-envelope monthly token cost estimate."""
    monthly_tokens = daily_tasks * 30 * avg_tokens_per_task
    monthly_cost = monthly_tokens * price_per_m / 1_000_000
    return {
        "monthly_tokens": monthly_tokens,
        "monthly_cost_usd": round(monthly_cost, 2),
        "annual_cost_usd": round(monthly_cost * 12, 2),
    }

# 1,000 tasks/day, 5,000 tokens each
print(quick_estimate(1000, 5000))
# {'monthly_tokens': 150000000, 'monthly_cost_usd': 750.0, 'annual_cost_usd': 9000.0}
